#[derive(Copy, Clone)]
struct Point {
    x: f64,
    y: f64,
}

// Copy: implicit, bitwise, cheap
let a: i32 = 5;
let b = a; // Copy

// Clone: explicit, may be expensive
let s1 = String::from("hello");
let s2 = s1.clone(); // Clone

let s = String::from("hello");
let r = &s;
println!("{r}");

let s = String::from("hello");
let r1 = &s;
let r2 = &s;
println!("{r1} {r2}");

fn calculate_length(s: &String) -> usize {
    s.len()
}
let s = String::from("hello");
let len = calculate_length(&s);
println!("{s} has length {len}");

let s = String::from("hello");
let r = &s;
// r.push_str(" world"); // ERROR: cannot mutate

let mut s = String::from("hello");
let r = &mut s;
r.push_str(" world");
println!("{r}");

let mut s = String::from("hello");
let r1 = &mut s;
// let r2 = &mut s; // ERROR: second mutable borrow
r1.push_str(" world");

let mut s = String::from("hello");
let r1 = &s;
let r2 = &s;
// let r3 = &mut s; // ERROR while r1 and r2 are in use
println!("{r1} {r2}");

let mut s = String::from("hello");
let r1 = &s;
println!("{r1}");
// r1 is no longer used after this point
let r2 = &mut s; // OK: r1's lifetime has ended
r2.push_str(" world");

